// Type changes from 'div' to 'span' — entire subtree torn down
function Toggle({ asSpan }) {
  return asSpan
    ? <span className="box"><Child /></span>
    : <div  className="box"><Child /></div>;
}
// When asSpan flips, <Child /> unmounts and remounts.
// Its state (useState, refs) is reset.

// Type changes from ComponentA to ComponentB — same result
function Panel({ useNew }) {
  return useNew ? <NewPanel /> : <OldPanel />;
}
// Even if NewPanel and OldPanel render identical JSX,
// swapping them unmounts OldPanel and mounts NewPanel.
// All OldPanel state is lost.

// Previous render
<div id="container" className="card active" tabIndex={0}>
  text
</div>

// Next render
<div id="container" className="card" aria-label="info">
  text
</div>

// DOM operations React performs:
// 1. element.className = 'card'           (changed)
// 2. element.setAttribute('aria-label', 'info')  (added)
// 3. element.removeAttribute('tabIndex')  (removed)
// No-op: id = 'container'                (unchanged)
// No-op: text node                       (unchanged)

// Both renders produce 3 <li> nodes
// Previous: key A, B, C
// New:      key A, D, B  (D is new, C is removed, B moved)

// React builds map: { A: fiberA, B: fiberB, C: fiberC }

// Walk new children:
// key A → found in map → UPDATE in place (position 0→0, no move)
// key D → NOT in map  → INSERT new Fiber, new DOM node
// key B → found in map → UPDATE, needs to MOVE (position 1→2)

// Keys remaining in map after walk:
// key C → DELETE — remove DOM node, run cleanup effects

// Without key: React reuses the same UserForm instance
// and tries to update props — old form state (input values) persists
function App({ userId }) {
  return <UserForm userId={userId} />;
}

// With key: changing userId causes full unmount + remount
// Form state is reset to the new user's initial values
function App({ userId }) {
  return <UserForm key={userId} userId={userId} />;
}

// Demonstrate the index-key problem
const items = ['Cherry', 'Apple', 'Banana'];

// With index keys: prepend 'Plum'
// Previous: Plum@0  Cherry@1  Apple@2  Banana@3  (new order)
// React sees: key 0 changed text 'Cherry'→'Plum',
//             key 1 changed text 'Apple'→'Cherry',
//             key 2 changed text 'Banana'→'Apple',
//             key 3 is new — INSERT 'Banana'
// Three UPDATE + one INSERT instead of one INSERT

// With ID keys: React correctly identifies one insertion at position 0
['Plum', 'Cherry', 'Apple', 'Banana']
  .map(fruit => <li key={fruit}>{fruit}</li>)

function App({ isPremium }) {
  return (
    <div>
      {isPremium
        ? <PremiumDashboard />   // position 0 when true
        : <FreeDashboard />      // position 0 when false
      }
    </div>
  );
}
// Switching isPremium: type changes at position 0 → full unmount + remount.
// PremiumDashboard state (e.g. open panels) is lost.

// Fix 1: one component, different props
function App({ isPremium }) {
  return <Dashboard premium={isPremium} />;
}

// Fix 2: render both, control visibility (preserves state for both)
function App({ isPremium }) {
  return (
    <>
      <PremiumDashboard style={{ display: isPremium ? 'block' : 'none' }} />
      <FreeDashboard    style={{ display: isPremium ? 'none'  : 'block' }} />
    </>
  );
}

// Fix 3: explicit key to intentionally reset state on switch
function App({ isPremium }) {
  return <Dashboard key={isPremium ? 'premium' : 'free'} premium={isPremium} />;
}

// Pattern 1: early return — different components at position 0
function Widget({ isLoading }) {
  if (isLoading) return <Spinner />;      // position 0 = Spinner
  return <Content />;                     // position 0 = Content
}
// Switching isLoading: unmounts Spinner, mounts Content (type change at pos 0)

// Pattern 2: inline ternary — same positions maintained
function Widget({ isLoading }) {
  return (
    <div>
      {isLoading ? <Spinner /> : null}  {/* pos 0 */}
      {isLoading ? null : <Content />}  {/* pos 1 */}
    </div>
  );
}
// Spinner and Content each have stable positions — React knows which is which.

// Pattern 3: logical && — position varies with condition
function Widget({ isLoading }) {
  return (
    <div>
      {isLoading && <Spinner />}   {/* pos 0: Spinner OR null */}
      <Content />                   {/* pos 0 when Spinner is null, pos 1 otherwise */}
    </div>
  );
}
// When isLoading flips false, Content shifts from pos 1 to pos 0 — type change!
// React remounts Content. Use null instead of && to keep Content at pos 1.

// Each person has two <dt>/<dd> siblings — needs a fragment with key
function DefinitionList({ people }) {
  return (
    <dl>
      {people.map(person => (
        <React.Fragment key={person.id}>
          <dt>{person.name}</dt>
          <dd>{person.role}</dd>
        </React.Fragment>
      ))}
    </dl>
  );
}
// Without key on Fragment, React cannot track each person's
// dt+dd pair as a unit across list mutations.

function Matrix({ rows }) {
  return (
    <table>
      <tbody>
        {rows.map(row => (
          <tr key={row.id}>                {/* row key */}
            {row.cells.map(cell => (
              <td key={cell.id}>{cell.value}</td>  {/* cell key */}
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );
}

// Anti-pattern: component defined inside render
function Parent() {
  // New function reference on every render
  function Child() { return <p>child</p>; }
  return <Child />;  // full remount every time Parent renders
}

// Fix: hoist to module level
function Child() { return <p>child</p>; }
function Parent() {
  return <Child />;  // same type reference → update, not remount
}

// Anti-pattern: mutating state
function Counter() {
  const [items, setItems] = useState([]);
  function add(item) {
    items.push(item);          // mutates — React won't re-render
    setItems(items);           // same reference, React bails out
  }
}

// Fix: new reference
function Counter() {
  const [items, setItems] = useState([]);
  function add(item) {
    setItems(prev => [...prev, item]);  // new array → re-render
  }
}

import { flushSync } from 'react-dom';

function ScrollToBottom({ messages }) {
  const endRef = useRef(null);

  function addMessage(text) {
    // flushSync: commit the new message to the DOM immediately
    flushSync(() => {
      setMessages(prev => [...prev, { id: Date.now(), text }]);
    });
    // By here, the DOM has been updated — safe to scroll
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }

  return (
    <div>
      {messages.map(m => <p key={m.id}>{m.text}</p>)}
      <div ref={endRef} />
    </div>
  );
}

// React treats these differently during reconciliation:

// Uncontrolled — React sets defaultValue once on mount, then ignores it
<input defaultValue="initial" />

// Controlled — React sets value on every commit, reads element.value to detect changes
<input value={state} onChange={e => setState(e.target.value)} />

// Key insight: React does NOT use setAttribute('value', ...) for inputs.
// It uses the DOM property element.value so the browser cursor position
// and selection state are preserved across re-renders.

import { render, screen } from '@testing-library/react';

test('reuses instance when key is stable', () => {
  const { rerender } = render(<Counter initialCount={0} key="counter" />);

  // Increment internal state
  userEvent.click(screen.getByRole('button'));
  expect(screen.getByText('1')).toBeInTheDocument();

  // Re-render with same key — React keeps the same instance
  rerender(<Counter initialCount={5} key="counter" />);
  // count remains 1 (internal state preserved), even though initialCount changed
  expect(screen.getByText('1')).toBeInTheDocument();
});

test('resets state when key changes', () => {
  const { rerender } = render(<Counter initialCount={0} key="a" />);
  userEvent.click(screen.getByRole('button'));
  expect(screen.getByText('1')).toBeInTheDocument();

  // Different key → unmount + remount
  rerender(<Counter initialCount={0} key="b" />);
  expect(screen.getByText('0')).toBeInTheDocument(); // state reset
});

import { startTransition, useState } from 'react';

function FilteredList({ items }) {
  const [filter, setFilter] = useState('');
  const [filtered, setFiltered] = useState(items);

  function handleInput(e) {
    const value = e.target.value;
    setFilter(value); // urgent: update the input immediately

    startTransition(() => {
      // Low priority: computing filtered list may be interrupted
      // if the user types again before this render commits
      setFiltered(items.filter(i => i.name.includes(value)));
    });
  }

  return (
    <>
      <input value={filter} onChange={handleInput} />
      <ul>
        {filtered.map(i => <li key={i.id}>{i.name}</li>)}
      </ul>
    </>
  );
}
